const body = $input.first().json;

// Facebook Lead Ads webhook delivers field_data as array of {name, values} pairs
// Support both raw FB webhook format and pre-parsed format
let fields = {};

if (body.field_data && Array.isArray(body.field_data)) {
  body.field_data.forEach(f => {
    fields[f.name] = f.values && f.values[0] ? f.values[0] : '';
  });
} else if (body.changes && Array.isArray(body.changes)) {
  // Nested FB webhook format
  const leadData = body.changes[0] && body.changes[0].value;
  if (leadData && leadData.field_data) {
    leadData.field_data.forEach(f => {
      fields[f.name] = f.values && f.values[0] ? f.values[0] : '';
    });
  }
} else {
  // Already flat (pre-parsed)
  fields = body;
}

const full_name = fields.full_name || fields.name || '';
const nameParts = full_name.trim().split(' ');
const first_name = fields.first_name || nameParts[0] || '';
const last_name = fields.last_name || nameParts.slice(1).join(' ') || '';
const email = (fields.email || '').toLowerCase().trim();
const phone = (fields.phone_number || fields.phone || '').replace(/[^\d+]/g, '');
const service = fields.service || fields.services_interested || fields.what_service || '';
const address = fields.street_address || fields.address || fields.zip_code || '';

// FB lead-level metadata
const form_id = body.form_id || (body.changes && body.changes[0] && body.changes[0].value && body.changes[0].value.form_id) || '';
const ad_id = body.ad_id || (body.changes && body.changes[0] && body.changes[0].value && body.changes[0].value.ad_id) || '';
const campaign_id = body.campaign_id || '';

// Score: paid source baseline
let score = 20;
const factors = ['Facebook Lead Ad (+20)'];
if (phone) { score += 5; factors.push('Has phone (+5)'); }
if (email) { score += 5; factors.push('Has email (+5)'); }
if (address) { score += 5; factors.push('Has address (+5)'); }

const service_lower = service.toLowerCase();
const highValue = ['hardscaping', 'commercial', 'patio', 'irrigation', 'landscape design'];
const midValue = ['fertilization', 'aeration', 'mowing', 'lawn care', 'overseeding'];
if (highValue.some(s => service_lower.includes(s))) { score += 20; factors.push('High-value service (+20)'); }
else if (midValue.some(s => service_lower.includes(s))) { score += 10; factors.push('Mid-value service (+10)'); }

const finalScore = Math.min(score, 100);
let lead_tier = 'cold';
if (finalScore >= 70) lead_tier = 'hot';
else if (finalScore >= 50) lead_tier = 'warm';
else if (finalScore >= 30) lead_tier = 'standard';

return {
  json: {
    first_name,
    last_name,
    email,
    phone,
    service,
    address,
    source: 'facebook_ads',
    fb_form_id: form_id,
    fb_ad_id: ad_id,
    fb_campaign_id: campaign_id,
    lead_score: finalScore,
    lead_tier,
    score_factors: factors,
    raw_payload: JSON.stringify(body)
  }
};

const leadData = $('Parse Facebook Lead').first().json;
const insertResult = $input.first().json;
const lead_id = Array.isArray(insertResult) ? (insertResult[0] && insertResult[0].id) : (insertResult && insertResult.id);

return {
  json: {
    ...leadData,
    lead_id: lead_id || null
  }
};

const data = $('Extract Lead ID').first().json;

return {
  json: {
    success: true,
    lead_id: data.lead_id,
    score: data.lead_score,
    tier: data.lead_tier,
    source: 'facebook_ads'
  }
};
